use std::collections::BTreeMap;
use std::fmt::{self, Write};
use std::path::PathBuf;
use std::process::Command;

use crate::agent::{AgentBackend, AgentError, AgentId, AgentLaunch, AgentProfile};

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct AgentCommit {
    pub hash: String,
    pub agent_id: AgentId,
    pub feature: String,
    pub reason: String,
    pub context: String,
    pub subject: String,
    pub body: String,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct GitHistory {
    root: PathBuf,
}

impl GitHistory {
    pub fn new(root: PathBuf) -> Self {
        Self { root }
    }

    pub fn latest_agent_commits(&self) -> Result<Vec<AgentCommit>, ReviewError> {
        let output = Command::new("git")
            .current_dir(&self.root)
            .args(["log", "--pretty=format:%H%x1f%B%x1e"])
            .output()
            .map_err(ReviewError::Io)?;
        if !output.status.success() {
            return Err(ReviewError::History(
                String::from_utf8_lossy(&output.stderr).trim().to_string(),
            ));
        }

        let mut latest = BTreeMap::new();
        for record in String::from_utf8_lossy(&output.stdout).split('\x1e') {
            let record = record.trim();
            if record.is_empty() {
                continue;
            }
            let Some(commit) = parse_agent_commit(record)? else {
                continue;
            };
            latest.entry(commit.agent_id.clone()).or_insert(commit);
        }

        Ok(latest.into_values().collect())
    }

    pub fn latest_agent_review_commits(
        &self,
        reviewed_agent_commits: &BTreeMap<AgentId, String>,
        agent_baselines: &BTreeMap<AgentId, String>,
    ) -> Result<Vec<AgentCommit>, ReviewError> {
        let latest = self.latest_agent_commits()?;
        let mut targets = Vec::new();
        for commit in latest {
            if reviewed_agent_commits
                .get(&commit.agent_id)
                .is_some_and(|hash| hash == &commit.hash)
            {
                continue;
            }
            let boundary = reviewed_agent_commits
                .get(&commit.agent_id)
                .or_else(|| agent_baselines.get(&commit.agent_id))
                .map(String::as_str);
            if let Some(target) = self.agent_review_commit(&commit.agent_id, boundary)? {
                targets.push(target);
            }
        }
        Ok(targets)
    }

    pub fn agent_commit(&self, hash: &str) -> Result<Option<AgentCommit>, ReviewError> {
        let output = Command::new("git")
            .current_dir(&self.root)
            .args(["show", "--no-patch", "--pretty=format:%H%x1f%B%x1e", hash])
            .output()
            .map_err(ReviewError::Io)?;
        if !output.status.success() {
            return Err(ReviewError::History(
                String::from_utf8_lossy(&output.stderr).trim().to_string(),
            ));
        }

        parse_agent_commit(String::from_utf8_lossy(&output.stdout).trim())
    }

    pub fn agent_review_commit(
        &self,
        agent_id: &AgentId,
        boundary: Option<&str>,
    ) -> Result<Option<AgentCommit>, ReviewError> {
        let records = self.agent_commits_in_range(boundary)?;
        let commits = if boundary.is_some() {
            records
                .into_iter()
                .filter(|commit| &commit.agent_id == agent_id)
                .collect()
        } else {
            latest_contiguous_agent_commits(records, agent_id)
        };
        Ok(combine_agent_review_commits(commits))
    }

    pub fn head_hash(&self) -> Result<Option<String>, ReviewError> {
        let output = Command::new("git")
            .current_dir(&self.root)
            .args(["rev-parse", "--verify", "HEAD"])
            .output()
            .map_err(ReviewError::Io)?;
        if !output.status.success() {
            return Ok(None);
        }
        Ok(Some(
            String::from_utf8_lossy(&output.stdout).trim().to_string(),
        ))
    }

    fn agent_commits_in_range(
        &self,
        boundary: Option<&str>,
    ) -> Result<Vec<AgentCommit>, ReviewError> {
        let mut args = vec![
            "log".to_string(),
            "--pretty=format:%H%x1f%B%x1e".to_string(),
        ];
        let range;
        if let Some(boundary) = boundary {
            range = format!("{boundary}..HEAD");
            args.push(range);
        }
        let output = Command::new("git")
            .current_dir(&self.root)
            .args(args)
            .output()
            .map_err(ReviewError::Io)?;
        if !output.status.success() {
            return Err(ReviewError::History(
                String::from_utf8_lossy(&output.stderr).trim().to_string(),
            ));
        }

        let mut commits = Vec::new();
        for record in String::from_utf8_lossy(&output.stdout).split('\x1e') {
            let record = record.trim();
            if record.is_empty() {
                continue;
            }
            let Some(commit) = parse_agent_commit(record)? else {
                continue;
            };
            commits.push(commit);
        }
        Ok(commits)
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ReviewResult {
    pub agent_id: AgentId,
    pub reviewer_id: AgentId,
    pub commit: AgentCommit,
    pub rounds: usize,
    pub findings_resolved: bool,
}

#[derive(Debug)]
pub struct ReviewCoordinator<B> {
    root: PathBuf,
    backend: B,
    agent_profile: AgentProfile,
    max_rounds: usize,
}

impl<B> ReviewCoordinator<B>
where
    B: AgentBackend,
{
    pub fn new(root: PathBuf, backend: B) -> Self {
        Self {
            root,
            backend,
            agent_profile: AgentProfile::codex(),
            max_rounds: 8,
        }
    }

    pub fn with_agent_profile(mut self, agent_profile: AgentProfile) -> Self {
        self.agent_profile = agent_profile;
        self
    }

    pub fn with_max_rounds(mut self, max_rounds: usize) -> Self {
        self.max_rounds = max_rounds.max(1);
        self
    }

    pub fn into_backend(self) -> B {
        self.backend
    }

    pub fn review_latest_agent_commits(&mut self) -> Result<Vec<ReviewResult>, ReviewError> {
        let commits = GitHistory::new(self.root.clone())
            .latest_agent_review_commits(&BTreeMap::new(), &BTreeMap::new())?;
        commits
            .into_iter()
            .map(|commit| self.review_commit(commit))
            .collect()
    }

    fn review_commit(&mut self, commit: AgentCommit) -> Result<ReviewResult, ReviewError> {
        let summary_prompt = format!(
            "Please summarize the full reviewed patch scope for Agent-ID {}.\nLatest commit: {}\nFeature: {}\nReason: {}\nReview scope:\n{}\n\nFocus on what behavior the cumulative patch changes.",
            commit.agent_id, commit.hash, commit.feature, commit.reason, commit.context
        );
        let summary = self
            .backend
            .send(&commit.agent_id, &summary_prompt)
            .map_err(ReviewError::Agent)?
            .text;

        let reviewer_id = AgentId::new(format!("review-{}", commit.agent_id.as_str()))
            .map_err(ReviewError::Agent)?;
        let review_prompt = format!(
            "Review the full patch scope for Agent-ID {}.\nLatest commit: {}\nFeature: {}\nReason: {}\nReview scope:\n{}\nSummary from original agent:\n{}\n\nReview every commit listed in the review scope and reply with NO_FINDINGS if there are no findings. Otherwise reply with FINDINGS followed by the issues.",
            commit.agent_id, commit.hash, commit.feature, commit.reason, commit.context, summary
        );
        let reviewer_session = self
            .backend
            .launch(AgentLaunch::new(
                reviewer_id.clone(),
                self.agent_profile.kind.clone(),
                format!("review {}", commit.feature),
                review_prompt,
            ))
            .map_err(ReviewError::Agent)?;
        let mut review_text = reviewer_session
            .messages
            .last()
            .map(|message| message.text.clone())
            .unwrap_or_default();
        let mut rounds = 1;

        while !has_no_findings(&review_text) && rounds < self.max_rounds {
            let fix_prompt = format!(
                "The reviewer found issues in your patch for commit {}.\n{}\n\nPlease fix the patch through the orchestrator patch flow.",
                commit.hash, review_text
            );
            self.backend
                .send(&commit.agent_id, &fix_prompt)
                .map_err(ReviewError::Agent)?;

            let recheck_prompt = format!(
                "The original agent has responded to the findings for commit {}. Please check the patch again and reply with NO_FINDINGS if resolved, otherwise list remaining FINDINGS.",
                commit.hash
            );
            review_text = self
                .backend
                .send(&reviewer_id, &recheck_prompt)
                .map_err(ReviewError::Agent)?
                .text;
            rounds += 1;
        }

        Ok(ReviewResult {
            agent_id: commit.agent_id.clone(),
            reviewer_id,
            findings_resolved: has_no_findings(&review_text),
            rounds,
            commit,
        })
    }
}

fn parse_agent_commit(record: &str) -> Result<Option<AgentCommit>, ReviewError> {
    let Some((hash, body)) = record.split_once('\x1f') else {
        return Ok(None);
    };
    let Some(agent_id) = metadata_value(body, "Agent-ID:") else {
        return Ok(None);
    };
    let feature = metadata_value(body, "Feature:").unwrap_or_default();
    let reason = metadata_value(body, "Reason:").unwrap_or_default();
    let context = metadata_value(body, "Context:").unwrap_or_default();
    let subject = body.lines().next().unwrap_or_default().to_string();
    Ok(Some(AgentCommit {
        hash: hash.trim().to_string(),
        agent_id: AgentId::new(agent_id).map_err(ReviewError::Agent)?,
        feature,
        reason,
        context,
        subject,
        body: body.trim().to_string(),
    }))
}

fn latest_contiguous_agent_commits(
    commits: Vec<AgentCommit>,
    agent_id: &AgentId,
) -> Vec<AgentCommit> {
    let mut selected = Vec::new();
    let mut found_latest = false;
    for commit in commits {
        if &commit.agent_id == agent_id {
            found_latest = true;
            selected.push(commit);
        } else if found_latest {
            break;
        }
    }
    selected
}

use std::collections::VecDeque;
use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

use work_leaf::{
    AgentBackend, AgentError, AgentId, AgentKind, AgentLaunch, AgentProfile, AgentSession,
    ChatMessage, CommandChat, MessageRole, WorkLeafController, WorkLeafEvent, WorkLeafLoading,
};

#[test]
fn controller_exposes_ui_neutral_events_and_snapshot_without_terminal_ui() {
    let backend = FakeBackend::new(["launch reply", "follow reply"]);
    let chat = CommandChat::new(PathBuf::from("/repo"), backend);
    let mut controller = WorkLeafController::new(chat);

    let agent_id = controller
        .create_agent("implement parser combinator")
        .unwrap();

    assert_eq!(agent_id, AgentId::new("user-1").unwrap());
    assert!(controller.drain_events().iter().any(|event| {
        matches!(event, WorkLeafEvent::AgentAdded { session } if session.id == agent_id)
    }));
    let starting = controller.snapshot();
    let session = starting.session(&agent_id).expect("session exists");
    assert_eq!(session.title, "user-agent");
    assert_eq!(session.loading, Some(WorkLeafLoading::Launching));

    assert!(controller.wait_for_idle(Duration::from_secs(1)));
    let ready = controller.snapshot();
    let session = ready.session(&agent_id).expect("session exists");
    assert_eq!(session.title, "parser-combinator");
    assert_eq!(session.loading, None);
    assert!(session.lines.iter().any(|line| line == "launch reply"));

